17	const PROCESSING_FEE = 5;
18	const DEFAULT_BASE_PREMIUM = 100;
19	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	
30	function basePremiumFor(item: Item): number {
31	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
32	  const highEnchantmentSurcharge =
33	    item.enchantment === 5 ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
34	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
35	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
36	}
37	
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const LOYALTY_MIN_YEARS = 2;
43	
44	function applyLoyaltyDiscount(
45	  basePremium: number,
46	  yearsWithMHPCO: number | undefined,
47	): number {
48	  const qualifies =
49	    yearsWithMHPCO !== undefined && yearsWithMHPCO >= LOYALTY_MIN_YEARS;
50	  return qualifies ? basePremium * (1 - LOYALTY_DISCOUNT_RATE) : basePremium;
51	}
52	
53	function groupByType(items: Item[]): Map<string, Item[]> {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type) ?? [];
57	    group.push(item);
58	    groups.set(item.type, group);
59	  }
60	  return groups;
61	}
62	
63	function basePremiumForGroup(group: Item[]): number {
64	  if (group.length === BLOCK_SIZE) {
65	    return BLOCK_PREMIUM;
66	  }
67	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
68	}
69	
70	export function quote(input: QuoteInput): QuoteResult {
71	  const groups = [...groupByType(input.items).values()];
72	  const basePremium = groups.reduce(
73	    (sum, group) => sum + basePremiumForGroup(group),
74	    0,
75	  );
76	
77	  const policyBase = applyLoyaltyDiscount(basePremium, input.yearsWithMHPCO);
78	
79	  return { premium: policyBase + PROCESSING_FEE };
80	}
